// Skapa lokal tid i format YYYY-MM-DD;HH:MM:SS
let d = new Date();
let pad = n => n.toString().padStart(2, "0");

let ts =
  d.getFullYear() + "-" +
  pad(d.getMonth() + 1) + "-" +
  pad(d.getDate()) + ";" +
  pad(d.getHours()) + ":" +
  pad(d.getMinutes()) + ":" +
  pad(d.getSeconds());

// topic
let topic = msg.topic || "";

// payload -> sträng (så filen blir läsbar även om payload är objekt)
let pl;
if (typeof msg.payload === "string") {
  pl = msg.payload;
} else {
  try { pl = JSON.stringify(msg.payload); }
  catch(e) { pl = String(msg.payload); }
}

// CSV-rad: date;time;topic;payload
// Obs: ersätt radbrytningar så varje MQTT blir en rad
pl = pl.replace(/\r?\n/g, " ");

msg.payload = ts + ";" + topic + ";" + pl;
return msg;

// GPS loggning till CSV - endast SINGLE-läge
//
// En rad skrivs per GPS-meddelande.
//
// Kolumner:
// local_date;local_time;profile;lat;lon;alt;hdop;sat;speed_kmh;fix_ok;msg_id;raw_json
//
// Kommentar:
// - Endast stöd för GPS mode=single
// - Hela originalpayloaden sparas i raw_json
// - Numeriska värden skrivs med kommatecken för Excel på svenska system

// Hjälpfunktion: fyll ut tal till två tecken, t.ex. 3 -> "03"
function pad(n) {
    return n.toString().padStart(2, '0');
}

// Hjälpfunktion: omvandla epoch-tid (sekunder) till lokal datum/tid
function fmtDateTimeFromEpoch(epochSeconds) {
    if (epochSeconds === undefined || epochSeconds === null || epochSeconds === '') {
        return { date: '', time: '' };
    }

    let d = new Date(Number(epochSeconds) * 1000);
    if (isNaN(d.getTime())) {
        return { date: '', time: '' };
    }

    return {
        date: d.getFullYear() + '-' + pad(d.getMonth() + 1) + '-' + pad(d.getDate()),
        time: pad(d.getHours()) + ':' + pad(d.getMinutes()) + ':' + pad(d.getSeconds())
    };
}

// Hjälpfunktion: formatera decimaltal och byt punkt till komma
function fmtNumComma(v, decimals) {
    if (v === undefined || v === null || v === '') return '';

    let num = Number(v);
    if (!Number.isFinite(num)) return '';

    let s = (decimals !== undefined) ? num.toFixed(decimals) : String(num);
    return s.replace('.', ',');
}

// Hjälpfunktion: formatera heltal
function fmtInt(v) {
    if (v === undefined || v === null || v === '') return '';

    let num = Number(v);
    if (!Number.isFinite(num)) return '';

    return String(Math.trunc(num));
}

// Hjälpfunktion: formatera boolean till text
function fmtBool(v) {
    if (v === undefined || v === null || v === '') return '';

    if (typeof v === 'boolean') {
        return v ? 'true' : 'false';
    }

    return String(v);
}

// Hjälpfunktion: skydda CSV-fält som innehåller ; eller citattecken
function csvEscape(v) {
    if (v === undefined || v === null) return '';

    let s = String(v);

    if (s.includes(';') || s.includes('"') || s.includes('\n') || s.includes('\r')) {
        s = '"' + s.replace(/"/g, '""') + '"';
    }

    return s;
}

// Hjälpfunktion: spara hela originalobjektet som JSON-sträng
function getRawJson(obj) {
    try {
        return JSON.stringify(obj);
    } catch (e) {
        return '';
    }
}

// Hämtar ut GPS-data ur payload.
// Stöd finns både för flat struktur och eventuell framtida p.fix-struktur.
function pickFix(p) {
    let fx = p.fix || {};

    return {
        // Position
        lat: (fx.lat !== undefined) ? fx.lat : p.lat,
        lon: (fx.lon !== undefined) ? fx.lon : p.lon,

        // Höjd - stöd för både alt och alt_m
        alt: (fx.alt !== undefined) ? fx.alt :
            (fx.alt_m !== undefined) ? fx.alt_m :
                (p.alt !== undefined) ? p.alt : p.alt_m,

        // HDOP
        hdop: (fx.hdop !== undefined) ? fx.hdop : p.hdop,

        // Satelliter - stöd för både sat och sats
        sat: (fx.sat !== undefined) ? fx.sat :
            (fx.sats !== undefined) ? fx.sats :
                (p.sat !== undefined) ? p.sat : p.sats,

        // Hastighet - stöd för både spd och speed_kmh
        spd: (fx.spd !== undefined) ? fx.spd :
            (fx.speed_kmh !== undefined) ? fx.speed_kmh : p.speed_kmh,

        // Fix-status
        fix_ok: (fx.fix_ok !== undefined) ? fx.fix_ok :
            (p.fix_ok !== undefined) ? p.fix_ok : p.valid
    };
}

// Bygger en CSV-rad i rätt kolumnordning
function makeRow(data) {
    return [
        data.local_date,
        data.local_time,
        data.profile,
        data.lat,
        data.lon,
        data.alt,
        data.hdop,
        data.sat,
        data.speed_kmh,
        data.fix_ok,
        data.msg_id,
        data.raw_json
    ].map(csvEscape).join(';');
}


// =========================
// Huvudlogik
// =========================

let p = msg.payload;

// Ignorera allt som inte är GPS
if (!p || p.type !== 'GPS') {
    return null;
}

// Ignorera allt som inte är single
if (p.mode !== 'single') {
    return null;
}

// Tid för raden: använd ts om den finns, annars epoch_utc
let ts = (p.ts !== undefined) ? p.ts : p.epoch_utc;
if (ts === undefined) {
    return null;
}

// Plocka ut GPS-data
let fix = pickFix(p);

// Lokal tid för CSV-raden
let dt = fmtDateTimeFromEpoch(ts);

// Hela originalpayloaden sparas också
let rawJson = getRawJson(p);

// Bygg CSV-rad
msg.payload = makeRow({
    local_date: dt.date,
    local_time: dt.time,
    profile: p.profile || '',
    lat: fmtNumComma(fix.lat, 6),
    lon: fmtNumComma(fix.lon, 6),
    alt: fmtNumComma(fix.alt, 1),
    hdop: fmtNumComma(fix.hdop, 1),
    sat: fmtInt(fix.sat),
    speed_kmh: fmtNumComma(fix.spd, 1),
    fix_ok: fmtBool(fix.fix_ok),
    msg_id: p.msg_id || '',
    raw_json: rawJson
});

return msg;
